  "modal.confirm.restore-version.title": "\u0412\u0440\u0430\u0442\u0438 \u0438\u0437\u0430\u0431\u0440\u0430\u043D\u0443 \u0432\u0435\u0440\u0437\u0438\u0458\u0443",
